import Foundation

// Define a logger class to handle logging
class Logger {
    static let shared = Logger()
    
    func log(_ message: String, level: LogLevel = .debug) {
        switch level {
        case .debug:
            print("[DEBUG] \(message)")
        case .info:
            print("[INFO] \(message)")
        case .warning:
            print("[WARNING] \(message)")
        case .error:
            print("[ERROR] \(message)")
        }
    }
}

// Define a LogLevel enum
enum LogLevel {
    case debug, info, warning, error
}

// Define an Analytics class to track user interactions and app behavior
class Analytics {
    func logAuthenticationFlow(with userId: String, email: String, token: String) {
        Logger.shared.log("User \(userId) authenticated with email \(email) and token \(token)")
    }
    
    func logAPIRequest(with method: String, url: String, payload: [String: Any]) {
        let request = "Method: \(method), URL: \(url), Payload: \(payload)"
        Logger.shared.log(request)
    }
    
    func logAPISuccessResponse(with response: [String: Any]) {
        let responseString = "\(response)"
        Logger.shared.log("API Response: \(responseString)")
    }
    
    func logAPIFailureResponse(with error: Error) {
        let errorMessage = "API Error: \(error.localizedDescription)"
        Logger.shared.log(errorMessage)
    }
    
    func logUserDataChange(with userId: String, data: [String: Any]) {
        let userDataString = "\(data)"
        Logger.shared.log("User \(userId) updated with data: \(userDataString)")
    }
}

